import{_ as r,o as t,c as o,ae as n}from"./chunks/framework.C8MNLDzb.js";const u=JSON.parse('{"title":"子部 · 诸子百家","description":"","frontmatter":{},"headers":[],"relativePath":"docs/子部/index.md","filePath":"docs/子部/index.md"}'),e={name:"docs/子部/index.md"};function s(i,a,h,l,g,d){return t(),o("div",null,[...a[0]||(a[0]=[n('<h1 id="子部-·-诸子百家" tabindex="-1">子部 · 诸子百家 <a class="header-anchor" href="#子部-·-诸子百家" aria-label="Permalink to &quot;子部 · 诸子百家&quot;">​</a></h1><blockquote><p>子部收录诸子百家著作，是中华哲学思想的核心宝库。百家争鸣，各有其道，呈现中华思想的多样性与深度。</p></blockquote><hr><h2 id="《庄子》典故" tabindex="-1">《庄子》典故 <a class="header-anchor" href="#《庄子》典故" aria-label="Permalink to &quot;《庄子》典故&quot;">​</a></h2><h3 id="庄周梦蝶" tabindex="-1">庄周梦蝶 <a class="header-anchor" href="#庄周梦蝶" aria-label="Permalink to &quot;庄周梦蝶&quot;">​</a></h3><p><strong>典故：</strong> 庄子梦见自己变成一只蝴蝶，翩翩飞舞，十分自在。醒来后却发现自己还是庄子。于是他疑惑：究竟是庄子梦见变成了蝴蝶，还是蝴蝶梦见变成了庄子？ <strong>出处：</strong> 《庄子·齐物论》 <strong>释义：</strong> 比喻人生如梦，世事无常。后也比喻艺术家陶醉于自己的创作中。</p><h3 id="望洋兴叹" tabindex="-1">望洋兴叹 <a class="header-anchor" href="#望洋兴叹" aria-label="Permalink to &quot;望洋兴叹&quot;">​</a></h3><p><strong>典故：</strong> 秋天涨水时，河伯以为自己是天下最壮大的，等他见到北海，才望洋向若而叹。 <strong>出处：</strong> 《庄子·秋水》 <strong>释义：</strong> 仰望海洋，发出感叹。比喻做事时因力量不够或缺乏条件而感到无可奈何。</p><h3 id="庖丁解牛" tabindex="-1">庖丁解牛 <a class="header-anchor" href="#庖丁解牛" aria-label="Permalink to &quot;庖丁解牛&quot;">​</a></h3><p><strong>典故：</strong> 有一个名叫丁的厨师替梁惠王宰牛，手所接触的地方都发出破裂的声音，而刀始终完好无损。 <strong>出处：</strong> 《庄子·养生主》 <strong>释义：</strong> 比喻技术纯熟，做事得心应手。</p><h3 id="涸辙之鱼" tabindex="-1">涸辙之鱼 <a class="header-anchor" href="#涸辙之鱼" aria-label="Permalink to &quot;涸辙之鱼&quot;">​</a></h3><p><strong>典故：</strong> 庄子家里断了粮去找监河侯借粮，监河侯说等收了赋税再借。庄子气愤地说：昨天我看到干涸的车辙里有一条鱼，它请求给他斗升之水活命，我说去引西江的水来救它。鱼说：&quot;那就等死后在鱼铺里见吧。&quot; <strong>出处：</strong> 《庄子·外物》 <strong>释义：</strong> 比喻在困境中急需救援。</p><h3 id="邯郸学步" tabindex="-1">邯郸学步 <a class="header-anchor" href="#邯郸学步" aria-label="Permalink to &quot;邯郸学步&quot;">​</a></h3><p><strong>典故：</strong> 燕国有个人到赵国首都邯郸去，看到赵国人走路姿势很美，就跟着学。结果不但没学会赵国的走法，反而把自己原来的走法也忘了，只能爬着回去。 <strong>出处：</strong> 《庄子·秋水》 <strong>释义：</strong> 比喻模仿别人不成，反而丧失了原有的技能。</p><hr><h2 id="《韩非子》典故" tabindex="-1">《韩非子》典故 <a class="header-anchor" href="#《韩非子》典故" aria-label="Permalink to &quot;《韩非子》典故&quot;">​</a></h2><h3 id="买椟还珠" tabindex="-1">买椟还珠 <a class="header-anchor" href="#买椟还珠" aria-label="Permalink to &quot;买椟还珠&quot;">​</a></h3><p><strong>典故：</strong> 楚国有个商人把珍珠装在漂亮的木匣子里到郑国去卖，郑国人买下木匣子，把珍珠还给了商人。 <strong>出处：</strong> 《韩非子·外储说左上》 <strong>释义：</strong> 比喻取舍失当，舍本逐末。</p><h3 id="守株待兔" tabindex="-1">守株待兔 <a class="header-anchor" href="#守株待兔" aria-label="Permalink to &quot;守株待兔&quot;">​</a></h3><p><strong>典故：</strong> 宋国有个农夫看见一只兔子撞死在树桩上，于是放下农具守着树桩，希望再得到兔子，结果再没有得到兔子，而他自己却被宋国人耻笑。 <strong>出处：</strong> 《韩非子·五蠹》 <strong>释义：</strong> 比喻死守狭隘经验，不知变通。</p><h3 id="滥竽充数" tabindex="-1">滥竽充数 <a class="header-anchor" href="#滥竽充数" aria-label="Permalink to &quot;滥竽充数&quot;">​</a></h3><p><strong>典故：</strong> 齐宣王喜欢听人吹竽，必须三百人一起吹。有个南郭先生根本不会吹竽，却混在乐队里装模作样。宣王死后，湣王即位，喜欢一个人一个人地吹，南郭先生只好逃走了。 <strong>出处：</strong> 《韩非子·内储说上》 <strong>释义：</strong> 比喻没有真才实学的人混在行家里面充数。</p><h3 id="自相矛盾" tabindex="-1">自相矛盾 <a class="header-anchor" href="#自相矛盾" aria-label="Permalink to &quot;自相矛盾&quot;">​</a></h3><p><strong>典故：</strong> 楚国有个卖盾和矛的人，先夸他的盾最坚固，什么都刺不穿；又夸他的矛最锋利，什么都能刺穿。有人问：&quot;用你的矛刺你的盾会怎么样？&quot;那人答不上来。 <strong>出处：</strong> 《韩非子·难一》 <strong>释义：</strong> 比喻言语或行为前后互相抵触。</p><h3 id="刻舟求剑" tabindex="-1">刻舟求剑 <a class="header-anchor" href="#刻舟求剑" aria-label="Permalink to &quot;刻舟求剑&quot;">​</a></h3><p><strong>典故：</strong> 楚国有人坐船过江时，把剑掉在水里，在船舷上刻了个记号，说：&quot;这里是我的剑掉下去的地方。&quot;等船靠岸后，他从刻记号的地方下水找剑。 <strong>出处：</strong> 《韩非子·难一》 <strong>释义：</strong> 比喻拘泥成例，不知道跟着情势的变化而改变。</p><hr><h2 id="子部代表作者" tabindex="-1">子部代表作者 <a class="header-anchor" href="#子部代表作者" aria-label="Permalink to &quot;子部代表作者&quot;">​</a></h2><h3 id="庄子-约公元前369年-公元前286年" tabindex="-1">庄子（约公元前369年-公元前286年） <a class="header-anchor" href="#庄子-约公元前369年-公元前286年" aria-label="Permalink to &quot;庄子（约公元前369年-公元前286年）&quot;">​</a></h3><p>名周，宋国蒙人，战国时期道家代表人物。《庄子》是道家经典，分为内篇、外篇、杂篇。其文想象丰富，语言幽默，富有哲理。</p><h3 id="韩非-约公元前280年-公元前233年" tabindex="-1">韩非（约公元前280年-公元前233年） <a class="header-anchor" href="#韩非-约公元前280年-公元前233年" aria-label="Permalink to &quot;韩非（约公元前280年-公元前233年）&quot;">​</a></h3><p>战国时期韩国人，法家集大成者。著有《韩非子》一书，主张以法治国，君主集权。</p><hr><h2 id="代表流派" tabindex="-1">代表流派 <a class="header-anchor" href="#代表流派" aria-label="Permalink to &quot;代表流派&quot;">​</a></h2><ul><li><strong>道家</strong> — 《老子》《庄子》，道法自然，无为而治</li><li><strong>儒家</strong> — 《论语》《孟子》，仁义礼智，君子之道</li><li><strong>墨家</strong> — 《墨子》，兼爱非攻，尚贤节用</li><li><strong>法家</strong> — 《韩非子》《商君书》，法治集权，富国强兵</li><li><strong>兵家</strong> — 《孙子兵法》，知己知彼，百战不殆</li></ul><hr><p><em>本文库由 GuoAgent 运营维护</em></p>',37)])])}const q=r(e,[["render",s]]);export{u as __pageData,q as default};
